// Normalize Google Sheet rows into BIH Intel API format
// Flexible column mapping — handles both snake_case and human-readable headers
const results = [];
const today = new Date().toISOString().slice(0, 10);

for (const item of $input.all()) {
  const r = item.json;

  const listing_id = String(
    r.listing_id || r['Listing ID'] || r.id || r.ID || ''
  ).trim();

  const title = String(
    r.title || r.Title || r.name || r.Name || r.description || ''
  ).trim();

  const priceRaw =
    r.price_cad ??
    r['Price (CAD)'] ??
    r['Price CAD'] ??
    r['price_cad'] ??
    r.price ??
    r.Price ??
    0;
  const price_cad = parseFloat(String(priceRaw).replace(/[^0-9.]/g, '')) || 0;

  const sale_date_raw = String(
    r.sale_date || r['Sale Date'] || r.date || r.Date || today
  ).trim();
  const dateValid = /^\d{4}-\d{2}-\d{2}$/.test(sale_date_raw);

  const category_raw =
    String(r.category_raw || r.category || r.Category || '').trim() || null;
  const location =
    String(r.location || r.Location || r.region || r.Region || '').trim() || null;
  const url =
    String(r.url || r.URL || r.link || r.Link || r.href || '').trim() || null;

  // Skip rows missing required fields
  if (!listing_id || !title || price_cad <= 0) continue;

  results.push({
    json: {
      listing_id: listing_id.slice(0, 100),
      title: title.slice(0, 255),
      price_cad,
      sale_date: dateValid ? sale_date_raw : today,
      category_raw: category_raw ? category_raw.slice(0, 100) : null,
      location: location ? location.slice(0, 100) : null,
      url: url ? url.slice(0, 500) : null
    }
  });
}

return results;

// Collect current batch items into a single JSON array for POST body
const rows = $input.all().map(i => i.json);
return [{ json: rows }];

// 200ms back-pressure guard between batches
// Gives Cloudflare D1 time to flush before next write
await new Promise(resolve => setTimeout(resolve, 200));
return $input.all();

// WF4 done — all batches submitted
// Actual insertion stats available at Intel Dashboard
const message = [
  '✅ *WF4 — RBA 历史数据全量导入完成*',
  '',
  '所有批次已提交至 BIH Intel API (`/ingest/rba/batch`)',
  '• Workers AI 正在对每条记录进行品类+品牌分类',
  '• 重复记录已通过 `INSERT OR IGNORE` 自动跳过',
  '',
  '📊 请前往 Intel Dashboard 核对实际插入条数：',
  'https://freightracing.ca/intel',
  '',
  '_确认数据无误后，请禁用本工作流（避免重复触发）_'
].join('\n');

return [{ json: { message } }];
